import {
  createRemoteJWKSet,
  customFetch,
  errors,
  jwtVerify,
  type FetchImplementation,
  type JWTPayload,
  type JWTVerifyGetKey,
} from "jose";

export interface TrustedOidcIssuer {
  allowedSigningAlgorithms: readonly string[];
  issuer: string;
  jwksUri: URL;
}

export interface VerifiedOidcToken {
  claims: JWTPayload;
  issuer: string;
  resolvedKeyId: string | null;
}

type OidcTokenVerifierFailureReason = "invalid_token" | "provider_failure" | "verifier_failure";

interface OidcTokenVerifierFailure {
  errorCode?: string;
  ok: false;
  providerStatus?: number;
  reason: OidcTokenVerifierFailureReason;
}

interface OidcTokenVerifierSuccess {
  ok: true;
  token: VerifiedOidcToken;
}

export type OidcTokenVerifierResult = OidcTokenVerifierFailure | OidcTokenVerifierSuccess;

export interface OidcTokenVerifierOptions {
  fetchJwks?: typeof fetch;
  issuer: TrustedOidcIssuer;
}

export class OidcTokenVerifier {
  readonly #issuer: TrustedOidcIssuer;
  readonly #remoteJwks: JWTVerifyGetKey;

  public constructor(options: OidcTokenVerifierOptions) {
    this.#issuer = options.issuer;
    this.#remoteJwks = remoteJwks(options.issuer.jwksUri, options.fetchJwks);
  }

  public async verify(token: string): Promise<OidcTokenVerifierResult> {
    try {
      const { payload, protectedHeader } = await jwtVerify(token, this.#remoteJwks, {
        algorithms: [...this.#issuer.allowedSigningAlgorithms],
        issuer: this.#issuer.issuer,
      });

      return {
        ok: true,
        token: {
          claims: payload,
          issuer: this.#issuer.issuer,
          resolvedKeyId: typeof protectedHeader.kid === "string" ? protectedHeader.kid : null,
        },
      };
    } catch (error) {
      return classifyVerificationError(error);
    }
  }
}

function remoteJwks(jwksUri: URL, fetchJwks: typeof fetch | undefined): JWTVerifyGetKey {
  const fetchImplementation = fetchJwks ?? fetch;

  return createRemoteJWKSet(jwksUri, {
    [customFetch]: ((url, options) =>
      fetchRemoteJwks(fetchImplementation, url, options)) satisfies FetchImplementation,
  });
}

class OidcProviderJwksError extends Error {
  public readonly code: string;
  public readonly providerStatus: number | undefined;

  public constructor(code: string, options: { cause?: unknown; providerStatus?: number } = {}) {
    super(
      "OIDC JWKS provider failure",
      options.cause === undefined ? undefined : { cause: options.cause },
    );
    this.code = code;
    this.name = "OidcProviderJwksError";
    this.providerStatus = options.providerStatus;
  }
}

async function fetchRemoteJwks(
  fetchImplementation: typeof fetch,
  url: Parameters<FetchImplementation>[0],
  options: Parameters<FetchImplementation>[1],
): Promise<Response> {
  let response: Response;

  try {
    response = await fetchImplementation(url, options);
  } catch (error) {
    throw new OidcProviderJwksError(
      hasErrorName(error, "TimeoutError") ? "ERR_OIDC_JWKS_TIMEOUT" : "ERR_OIDC_JWKS_FETCH_FAILED",
      { cause: error },
    );
  }

  if (response.status !== 200) {
    throw new OidcProviderJwksError("ERR_OIDC_JWKS_HTTP_STATUS", {
      providerStatus: response.status,
    });
  }

  let jwks: unknown;

  try {
    jwks = await response.clone().json();
  } catch (error) {
    throw new OidcProviderJwksError("ERR_OIDC_JWKS_JSON_PARSE_FAILED", { cause: error });
  }

  if (!isJsonWebKeySetShape(jwks)) {
    throw new OidcProviderJwksError("ERR_OIDC_JWKS_INVALID");
  }

  const headers = new Headers(response.headers);
  headers.set("content-type", "application/json");

  return new Response(response.body, {
    headers,
    status: response.status,
    statusText: response.statusText,
  });
}

function classifyVerificationError(error: unknown): OidcTokenVerifierFailure {
  const errorCode = errorCodeOf(error);

  if (error instanceof OidcProviderJwksError) {
    return providerFailure(errorCode, error.providerStatus);
  }

  if (error instanceof errors.JOSEError) {
    if (invalidTokenErrorCodes.has(error.code)) {
      return invalidTokenFailure(error.code);
    }

    if (providerFailureErrorCodes.has(error.code)) {
      return providerFailure(error.code);
    }

    return verifierFailure(error.code);
  }

  return verifierFailure(errorCode);
}

const invalidTokenErrorCodes = new Set([
  "ERR_JOSE_ALG_NOT_ALLOWED",
  // The caller controls the JWT header kid. If the provider returns a valid JWKS
  // that does not contain that key, treat the assertion as invalid rather than
  // retryable provider unavailability.
  "ERR_JWKS_NO_MATCHING_KEY",
  "ERR_JWS_INVALID",
  "ERR_JWS_SIGNATURE_VERIFICATION_FAILED",
  "ERR_JWT_CLAIM_VALIDATION_FAILED",
  "ERR_JWT_EXPIRED",
  "ERR_JWT_INVALID",
]);

const providerFailureErrorCodes = new Set([
  "ERR_JOSE_NOT_SUPPORTED",
  "ERR_JWK_INVALID",
  "ERR_JWKS_INVALID",
  "ERR_JWKS_MULTIPLE_MATCHING_KEYS",
  "ERR_JWKS_TIMEOUT",
]);

function invalidTokenFailure(errorCode?: string): OidcTokenVerifierFailure {
  return {
    ...(errorCode === undefined ? {} : { errorCode }),
    ok: false,
    reason: "invalid_token",
  };
}

function providerFailure(errorCode?: string, providerStatus?: number): OidcTokenVerifierFailure {
  return {
    ...(errorCode === undefined ? {} : { errorCode }),
    ok: false,
    ...(providerStatus === undefined ? {} : { providerStatus }),
    reason: "provider_failure",
  };
}

function verifierFailure(errorCode?: string): OidcTokenVerifierFailure {
  return {
    ...(errorCode === undefined ? {} : { errorCode }),
    ok: false,
    reason: "verifier_failure",
  };
}

function errorCodeOf(error: unknown): string | undefined {
  if (typeof error === "object" && error !== null && "code" in error) {
    const code = error.code;

    if (typeof code === "string") {
      return code;
    }
  }

  return undefined;
}

function hasErrorName(error: unknown, name: string): boolean {
  return (
    typeof error === "object" &&
    error !== null &&
    "name" in error &&
    typeof error.name === "string" &&
    error.name === name
  );
}

function isJsonWebKeySetShape(input: unknown): input is { keys: unknown[] } {
  return (
    typeof input === "object" &&
    input !== null &&
    "keys" in input &&
    Array.isArray(input.keys) &&
    input.keys.every((key) => typeof key === "object" && key !== null)
  );
}
import { importPKCS8, SignJWT } from "jose";

import {
  defaultGitHubApiDependencies,
  fetchGitHubApi,
  GitHubApiError,
  githubAcceptHeader,
  githubApiVersion,
  type GitHubApiDependencies,
  type GitHubApiEnv,
} from "./http.ts";
import { resolveSecretText, type SecretTextBinding } from "./secrets.ts";

const githubJwtLifetimeSeconds = 9 * 60;
const githubStatelessS2STokenHeader = "X-GitHub-Stateless-S2S-Token";

let cachedPrivateKey:
  | {
      readonly fingerprint: string;
      readonly imported: Promise<CryptoKey>;
    }
  | undefined;

export interface ResolvedGitHubAppInstallation {
  id: number;
}

export interface InstallationToken {
  expiresAt: string;
  permissions: Record<string, string>;
  token: string;
}

export type GitHubAppEnv = GitHubApiEnv & {
  GITHUB_APP_ID: string;
  GITHUB_APP_PRIVATE_KEY: SecretTextBinding;
};

interface GitHubInstallationResponse {
  id: number;
}

interface GitHubInstallationTokenResponse {
  expires_at: string;
  permissions?: Record<string, unknown>;
  token: string;
}

export async function resolveInstallationForRepository(
  env: GitHubAppEnv,
  repository: string,
  dependencies: GitHubApiDependencies = defaultGitHubApiDependencies,
): Promise<ResolvedGitHubAppInstallation> {
  const response = await fetchGitHubApi(
    env,
    `/repos/${repository}/installation`,
    await appAuthenticationHeaders(env),
    dependencies,
  );

  const body = (await response.json()) as GitHubInstallationResponse;

  if (typeof body.id !== "number") {
    throw new GitHubApiError(502, "invalid installation response");
  }

  return { id: body.id };
}

export async function createInstallationToken(
  env: GitHubAppEnv,
  installationId: number,
  repositoryId: string,
  permissions: Record<string, string> | undefined,
  dependencies: GitHubApiDependencies,
): Promise<InstallationToken> {
  const parsedRepositoryId = parseRepositoryId(repositoryId);

  if (parsedRepositoryId === null) {
    throw new GitHubApiError(400, "invalid repository id");
  }

  return createInstallationTokenWithBody(
    env,
    installationId,
    {
      repository_ids: [parsedRepositoryId],
    },
    permissions,
    dependencies,
  );
}

export async function createInstallationTokenForRepository(
  env: GitHubAppEnv,
  installationId: number,
  repository: string,
  permissions: Record<string, string> | undefined,
  dependencies: GitHubApiDependencies,
): Promise<InstallationToken> {
  const repositoryName = parseRepositoryName(repository);

  if (repositoryName === null) {
    throw new GitHubApiError(400, "invalid repository");
  }

  return createInstallationTokenWithBody(
    env,
    installationId,
    {
      repositories: [repositoryName],
    },
    permissions,
    dependencies,
  );
}

async function createInstallationTokenWithBody(
  env: GitHubAppEnv,
  installationId: number,
  repositorySelection: { repositories: string[] } | { repository_ids: number[] },
  permissions: Record<string, string> | undefined,
  dependencies: GitHubApiDependencies,
): Promise<InstallationToken> {
  const requestBody:
    | { permissions?: Record<string, string>; repositories: string[] }
    | { permissions?: Record<string, string>; repository_ids: number[] } = {
    ...repositorySelection,
  };

  if (permissions !== undefined) {
    requestBody.permissions = permissions;
  }

  const response = await fetchGitHubApi(
    env,
    `/app/installations/${installationId}/access_tokens`,
    await appAuthenticationHeaders(env),
    dependencies,
    {
      body: JSON.stringify(requestBody),
      headers: {
        "content-type": "application/json",
        [githubStatelessS2STokenHeader]: "enabled",
      },
      method: "POST",
    },
  );

  const responseBody = (await response.json()) as GitHubInstallationTokenResponse;

  if (
    typeof responseBody.token !== "string" ||
    typeof responseBody.expires_at !== "string" ||
    !isStringRecord(responseBody.permissions)
  ) {
    throw new GitHubApiError(502, "invalid installation token response");
  }

  return {
    expiresAt: responseBody.expires_at,
    permissions: responseBody.permissions,
    token: responseBody.token,
  };
}

/*
 * Installation token requests support either repository IDs or repository names.
 * cyspbot's token exchange flow uses repository names after resolving the target
 * installation from the same owner/repository resource.
 */
function parseRepositoryName(repository: string): string | null {
  const parts = repository.split("/");

  if (parts.length !== 2 || parts.some((part) => part.length === 0)) {
    return null;
  }

  return parts[1] ?? null;
}

async function appAuthenticationHeaders(env: GitHubAppEnv): Promise<HeadersInit> {
  const jwt = await createGitHubAppJwt(env);

  return {
    accept: githubAcceptHeader,
    authorization: `Bearer ${jwt}`,
    "user-agent": "cyspbot",
    "x-github-api-version": githubApiVersion,
  };
}

async function createGitHubAppJwt(env: GitHubAppEnv): Promise<string> {
  const privateKey = await importedGitHubAppPrivateKey(await githubAppPrivateKeyPem(env));
  const now = Math.floor(Date.now() / 1000);

  return new SignJWT({})
    .setProtectedHeader({ alg: "RS256" })
    .setIssuedAt(now - 60)
    .setExpirationTime(now + githubJwtLifetimeSeconds)
    .setIssuer(env.GITHUB_APP_ID)
    .sign(privateKey);
}

async function importedGitHubAppPrivateKey(privateKeyPem: string): Promise<CryptoKey> {
  const fingerprint = await privateKeyFingerprint(privateKeyPem);
  const cached = cachedPrivateKey;

  if (cached?.fingerprint === fingerprint) {
    return cached.imported;
  }

  const imported = importPKCS8(privateKeyPem, "RS256").catch(() => {
    throw new GitHubApiError(500, "invalid GitHub App private key");
  });
  cachedPrivateKey = { fingerprint, imported };

  return imported;
}

async function githubAppPrivateKeyPem(env: GitHubAppEnv): Promise<string> {
  const privateKeyPem = await resolveSecretText(env.GITHUB_APP_PRIVATE_KEY);

  if (privateKeyPem !== undefined && privateKeyPem.length > 0) {
    return privateKeyPem;
  }

  throw new GitHubApiError(500, "missing GitHub App private key");
}

function isStringRecord(value: unknown): value is Record<string, string> {
  if (value === null || typeof value !== "object" || Array.isArray(value)) {
    return false;
  }

  return Object.values(value).every((entry) => typeof entry === "string");
}

function parseRepositoryId(value: string): number | null {
  if (!/^(0|[1-9][0-9]*)$/u.test(value)) {
    return null;
  }

  const parsed = Number(value);

  return Number.isSafeInteger(parsed) ? parsed : null;
}

async function privateKeyFingerprint(privateKeyPem: string): Promise<string> {
  const digest = await crypto.subtle.digest("SHA-256", new TextEncoder().encode(privateKeyPem));

  return [...new Uint8Array(digest)].map((byte) => byte.toString(16).padStart(2, "0")).join("");
}
export const githubAcceptHeader = "application/vnd.github+json";
export const githubApiVersion = "2022-11-28";

export interface GitHubApiEnv {
  GITHUB_API_BASE_URL?: string;
}

export interface GitHubApiDependencies {
  fetch: typeof fetch;
}

export const defaultGitHubApiDependencies: GitHubApiDependencies = {
  fetch: (input, init) => fetch(input, init),
};

export class GitHubApiError extends Error {
  public readonly status: number;

  public constructor(status: number, message: string) {
    super(message);
    this.status = status;
  }
}

export async function fetchGitHubApi(
  env: GitHubApiEnv,
  path: string,
  headers: HeadersInit,
  dependencies: GitHubApiDependencies,
  init?: RequestInit,
): Promise<Response> {
  const requestHeaders = new Headers(headers);

  for (const [name, value] of new Headers(init?.headers)) {
    requestHeaders.set(name, value);
  }

  const baseUrl = env.GITHUB_API_BASE_URL ?? "https://api.github.com";
  const requestUrl = new URL(path.replace(/^\//u, ""), ensureTrailingSlash(baseUrl));

  const response = await dependencies.fetch(requestUrl, {
    ...init,
    headers: requestHeaders,
  });

  if (response.ok) {
    return response;
  }

  throw new GitHubApiError(response.status, `GitHub API request failed: ${path}`);
}

function ensureTrailingSlash(url: string): string {
  return url.endsWith("/") ? url : `${url}/`;
}
export type SecretTextBinding = string | SecretsStoreSecret;

export async function resolveSecretText(
  binding: SecretTextBinding | undefined,
): Promise<string | undefined> {
  if (binding === undefined || typeof binding === "string") {
    return binding;
  }

  return binding.get();
}
export type BoundedRequestBodyRead =
  | {
      bytes: Uint8Array;
      ok: true;
    }
  | {
      ok: false;
      status: 400 | 413;
    };

export async function readRequestBodyUpTo(
  request: Request,
  maxBytes: number,
): Promise<BoundedRequestBodyRead> {
  const contentLength = request.headers.get("content-length");

  if (contentLength !== null) {
    const parsedContentLength = parseContentLength(contentLength);

    if (parsedContentLength === null) {
      return { ok: false, status: 400 };
    }

    if (parsedContentLength > maxBytes) {
      return { ok: false, status: 413 };
    }
  }

  if (request.body === null) {
    return { bytes: new Uint8Array(), ok: true };
  }

  const reader = request.body.getReader();
  const chunks: Uint8Array[] = [];
  let totalBytes = 0;

  for (;;) {
    const read = await reader.read();

    if (read.done) {
      break;
    }

    totalBytes += read.value.byteLength;

    if (totalBytes > maxBytes) {
      await reader.cancel().catch(() => undefined);
      return { ok: false, status: 413 };
    }

    chunks.push(read.value);
  }

  const bytes = new Uint8Array(totalBytes);
  let offset = 0;

  for (const chunk of chunks) {
    bytes.set(chunk, offset);
    offset += chunk.byteLength;
  }

  return { bytes, ok: true };
}

function parseContentLength(value: string): number | null {
  if (!/^(0|[1-9][0-9]*)$/u.test(value)) {
    return null;
  }

  const parsed = Number(value);

  return Number.isSafeInteger(parsed) ? parsed : null;
}
interface ProblemDetails {
  status: number;
  title: string;
  type: string;
}

const statusTitles = new Map<number, string>([
  [400, "Bad Request"],
  [401, "Unauthorized"],
  [403, "Forbidden"],
  [404, "Not Found"],
  [405, "Method Not Allowed"],
  [413, "Payload Too Large"],
  [415, "Unsupported Media Type"],
  [429, "Too Many Requests"],
  [500, "Internal Server Error"],
  [502, "Bad Gateway"],
]);

function problemDetails(status: number): ProblemDetails {
  return {
    status,
    title: statusTitles.get(status) ?? "Unknown Error",
    type: "about:blank",
  };
}

export function jsonResponse(body: unknown, init?: ResponseInit): Response {
  const headers = new Headers(init?.headers);
  headers.set("content-type", "application/json; charset=utf-8");

  return new Response(JSON.stringify(body), {
    ...init,
    headers,
  });
}

export function problemResponse(status: number, headers?: HeadersInit): Response {
  const responseHeaders = new Headers(headers);
  responseHeaders.set("content-type", "application/problem+json; charset=utf-8");

  return new Response(JSON.stringify(problemDetails(status)), {
    status,
    headers: responseHeaders,
  });
}
import { jsonResponse, problemResponse } from "@cyspbot/http/problem-details";
import { acceptGitHubWebhookDelivery } from "./github-webhooks/acceptance.ts";
import type { GitHubWebhookReceiverDependencies } from "./dependencies.ts";

export async function handleGitHubWebhookRequest(
  request: Request,
  env: GitHubWebhookReceiverBindings,
  dependencies: GitHubWebhookReceiverDependencies,
): Promise<Response> {
  const result = await acceptGitHubWebhookDelivery(request, env, dependencies);

  if (result.kind === "accepted") {
    return jsonResponse(result.body, { status: result.status });
  }

  return problemResponse(result.status);
}
import type { GitHubWebhookReceiverDependencies as BaseGitHubWebhookReceiverDependencies } from "./github-webhooks/acceptance.ts";

export type GitHubWebhookReceiverDependencies = BaseGitHubWebhookReceiverDependencies;

export const defaultGitHubWebhookReceiverDependencies: GitHubWebhookReceiverDependencies = {
  now: () => new Date(),
};
import { problemResponse } from "@cyspbot/http/problem-details";
import {
  defaultGitHubWebhookReceiverDependencies,
  type GitHubWebhookReceiverDependencies,
} from "./dependencies.ts";
import { handleGitHubWebhookRequest } from "./webhook.ts";

export function createGitHubWebhookReceiverWorker(
  dependencies: GitHubWebhookReceiverDependencies = defaultGitHubWebhookReceiverDependencies,
): ExportedHandler<GitHubWebhookReceiverBindings> {
  return {
    fetch(request, env) {
      const url = new URL(request.url);

      if (url.pathname !== "/github/webhooks") {
        return problemResponse(404);
      }

      if (request.method !== "POST") {
        return problemResponse(405, { allow: "POST" });
      }

      return handleGitHubWebhookRequest(request, env, dependencies);
    },
  };
}

