import type { OidcIssuerAdapter } from "@cyspbot/oidc/issuer-adapter";
import type { TrustedOidcIssuer } from "@cyspbot/oidc";

const githubActionsIssuer = "https://token.actions.githubusercontent.com";
const githubActionsJwksUri = new URL(
  "https://token.actions.githubusercontent.com/.well-known/jwks",
);

export const githubActionsTrustedIssuer = {
  allowedSigningAlgorithms: ["RS256"],
  issuer: githubActionsIssuer,
  jwksUri: githubActionsJwksUri,
} satisfies TrustedOidcIssuer;

export const githubActionsIssuerAdapter = {
  canHandleIssuer: (issuer) => issuer === githubActionsTrustedIssuer.issuer,
  trustedIssuers: [githubActionsTrustedIssuer],
  validateSubjectTokenBinding: ({ claims, expectedAudience }) =>
    typeof claims.sub === "string" &&
    claims.sub.length > 0 &&
    typeof claims.exp === "number" &&
    (claims["azp"] === undefined || claims["azp"] === expectedAudience),
} satisfies OidcIssuerAdapter;
import type { OidcIssuerAdapter } from "@cyspbot/oidc/issuer-adapter";
import type { TrustedOidcIssuer } from "@cyspbot/oidc";

const flyOidcHost = "oidc.fly.io";
const flyOidcIssuerPrefix = `https://${flyOidcHost}/`;
const flyOrgSlugPattern = /^[a-z0-9][a-z0-9-]*[a-z0-9]$|^[a-z0-9]$/u;

export interface FlyMachineIssuerAdapterOptions {
  configuredOrgSlugs: readonly string[];
  runtimeOrgSlugs: string;
}

export function flyTrustedIssuerForOrgSlug(orgSlug: string): TrustedOidcIssuer | null {
  if (!flyOrgSlugPattern.test(orgSlug)) {
    return null;
  }

  const issuer = `https://${flyOidcHost}/${orgSlug}`;

  return {
    allowedSigningAlgorithms: ["RS256"],
    issuer,
    jwksUri: new URL(`${issuer}/.well-known/jwks`),
  };
}

export function parseConfiguredFlyOrgSlugs(value: string): readonly string[] | null {
  const slugs = value
    .split(",")
    .map((slug) => slug.trim())
    .filter((slug) => slug.length > 0);

  if (slugs.length === 0 || slugs.some((slug) => !flyOrgSlugPattern.test(slug))) {
    return null;
  }

  return slugs;
}

export function flyMachineIssuerAdapter(
  options: FlyMachineIssuerAdapterOptions,
): OidcIssuerAdapter {
  return {
    canHandleIssuer: (issuer) => issuer.startsWith(flyOidcIssuerPrefix),
    trustedIssuers: trustedFlyMachineIssuers(options),
    validateSubjectTokenBinding: ({ claims, expectedAudience }) =>
      typeof claims.sub === "string" &&
      claims.sub.length > 0 &&
      typeof claims.exp === "number" &&
      typeof claims.nbf === "number" &&
      (claims["azp"] === undefined || claims["azp"] === expectedAudience),
  };
}

function trustedFlyMachineIssuers(
  options: FlyMachineIssuerAdapterOptions,
): readonly TrustedOidcIssuer[] | null {
  const orgSlugs = new Set(options.configuredOrgSlugs);

  if (options.runtimeOrgSlugs.trim().length > 0) {
    const runtimeOrgSlugs = parseConfiguredFlyOrgSlugs(options.runtimeOrgSlugs);

    if (runtimeOrgSlugs === null) {
      return null;
    }

    for (const orgSlug of runtimeOrgSlugs) {
      orgSlugs.add(orgSlug);
    }
  }

  const issuers: TrustedOidcIssuer[] = [];

  for (const orgSlug of orgSlugs) {
    const issuer = flyTrustedIssuerForOrgSlug(orgSlug);

    if (issuer === null) {
      return null;
    }

    issuers.push(issuer);
  }

  return issuers;
}
import type { OidcIssuerAdapter } from "@cyspbot/oidc/issuer-adapter";
import type { TrustedOidcIssuer } from "@cyspbot/oidc";

const googleAccountsIssuer = "https://accounts.google.com";
const googleAccountsJwksUri = new URL("https://www.googleapis.com/oauth2/v3/certs");

export const googleServiceAccountTrustedIssuer = {
