+  flyOidcOrgSlugs: string;
+}
+
+export function configuredOidcIssuerAdapters(
+  runtimeConfig: OidcIssuerRuntimeConfig,
+): readonly OidcIssuerAdapter[] {
+  return [
+    ...(trustedOidcIssuerConfig.githubActions ? [githubActionsIssuerAdapter] : []),
