        },
      },
      ok: true,
    });
  });

  it("rejects Google service-account ID tokens whose authorized party differs from subject", async () => {
    const token = await createGoogleServiceAccountOidcToken({
      azp: "different-service-account-id",
    });

    await expect(
      authenticateOidcToken(
        token,
        "id_token",
        new Request("https://example.test/token"),
        cyspbotOidcAudience,
        testIssuerAdapters(),
        fetchOidcJwksTestDouble,
      ),
    ).resolves.toMatchObject({
      ok: false,
      reason: "invalid_token",
    });
  });

  it("rejects Google service-account ID tokens minted for another audience", async () => {
    const token = await createGoogleServiceAccountOidcToken(undefined, {
      audience: "https://example.test/token",
    });

    await expect(
      authenticateOidcToken(
        token,
        "id_token",
        new Request("https://example.test/token"),
        cyspbotOidcAudience,
        testIssuerAdapters(),
        fetchOidcJwksTestDouble,
      ),
    ).resolves.toMatchObject({
      ok: false,
      reason: "invalid_token",
    });
  });

  it("rejects GitHub JWT subject tokens without a non-empty subject claim", async () => {
    const token = await createOidcToken({ sub: "" });

    await expect(
      authenticateOidcToken(
        token,
        "jwt",
        new Request("https://example.test/token"),
        cyspbotOidcAudience,
        testIssuerAdapters(),
        fetchOidcJwksTestDouble,
      ),
    ).resolves.toMatchObject({
      ok: false,
      reason: "invalid_token",
    });
  });

  it("rejects unconfigured OIDC issuers without fetching their JWKS", async () => {
    let jwksFetches = 0;
    const token = await createGoogleServiceAccountOidcToken(undefined, {
      issuer: "https://accounts.example.invalid",
    });

    await expect(
      authenticateOidcToken(
        token,
        "id_token",
        new Request("https://example.test/token"),
        cyspbotOidcAudience,
        testIssuerAdapters(),
        async () => {
          jwksFetches += 1;

          return Response.json({ keys: [] });
        },
      ),
    ).resolves.toMatchObject({
      ok: false,
      reason: "invalid_token",
    });
    expect(jwksFetches).toBe(0);
  });

  it("does not let malformed Fly migration config block Google service-account issuers", async () => {
    const token = await createGoogleServiceAccountOidcToken();

    await expect(
      authenticateOidcToken(
        token,
        "id_token",
        new Request("https://example.test/token"),
        cyspbotOidcAudience,
        configuredOidcIssuerAdapters({
          flyOidcOrgSlugs: "https://oidc.fly.io/not-a-slug",
        }),
        fetchOidcJwksTestDouble,
      ),
    ).resolves.toMatchObject({
      context: {
        subjectToken: {
          issuer: "https://accounts.google.com",
        },
      },
      ok: true,
    });
  });
});

